sql:
SELECT courses.course_name, courses.location
FROM courses
JOIN races ON races.course = courses.course_id;

SELECT COUNT(*) 
FROM races 
WHERE course = (
  SELECT course_id 
  FROM courses
  WHERE capacity = (
    SELECT MAX(capacity) 
    FROM courses
  )
);

SELECT SUM(prize_money) 
FROM races 
WHERE race_name = '<race name>';

SELECT COUNT(*)
FROM access_logs
WHERE user_id = 'given_user_id';

external_knowledge:
- 'Initial bloom of success' metaphorically refers to positions 1 to 5;
- 'Navigating the shadows of the racing arena' symbolizes horses finishing in positions beyond the top 5 positions;
- 'Twilight' metaphorically refers to the latter part of a race, where the glory of winning is absent;
- 'Times and positions in this twilight zone' refers to the winning times and positions of horses that did not achieve top placements.

